import React, { useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';  // ← Изменено!
import { useSelector, useDispatch } from 'react-redux';
import { checkAuth } from './api';
import { loginSuccess, logout } from './store/authSlice';
import LoginPage from './LoginPage';
import MainPage from './MainPage';
import './styles.css';  // Если у вас есть глобальные стили

function App() {
  const isAuthenticated = useSelector(state => state.auth.isAuthenticated);
  const loading = useSelector(state => state.auth.loading);
  const dispatch = useDispatch();

  useEffect(() => {
    const verifyAuth = async () => {
      const authenticated = await checkAuth();
      if (authenticated) {
        const token = localStorage.getItem('token');
        const username = localStorage.getItem('username');
        dispatch(loginSuccess({ token, username }));
      }
    };

    verifyAuth();
  }, [dispatch]);

  const handleLogin = () => {
    const token = localStorage.getItem('token');
    const username = localStorage.getItem('username');
    dispatch(loginSuccess({ token, username }));
  };

  const handleLogout = () => {
    dispatch(logout());
  };

  if (loading) {
    return (
      <div style={{
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
        height: '100vh',
        fontSize: '1.5rem'
      }}>
        Загрузка...
      </div>
    );
  }

  return (
    <HashRouter>
      {/* HashRouter работает с #/ в URL, не требует basename */}
      <div className="App">
        <Routes>
          <Route
            path="/login"
            element={
              isAuthenticated ?
              <Navigate to="/" replace /> :
              <LoginPage onLogin={handleLogin} />
            }
          />
          <Route
            path="/"
            element={
              isAuthenticated ?
              <MainPage onLogout={handleLogout} /> :
              <Navigate to="/login" replace />
            }
          />
          {/* Добавьте другие routes по необходимости */}
          <Route path="*" element={<Navigate to="/" replace />} />
        </Routes>
      </div>
    </HashRouter>
  );
}

export default App;
